async function handleRequest(request) {
  // Set up CORS headers
  const corsHeaders = {
    'Access-Control-Allow-Origin': '*',
    'Access-Control-Allow-Methods': 'GET,HEAD,POST,OPTIONS',
    'Access-Control-Max-Age': '86400',
    'Access-Control-Allow-Headers': request.headers.get('access-control-request-headers') || 'content-type'
  }

  // Handle preflight OPTIONS request
  if (request.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders })
  }

  // Forward the request to your backend service
  const url = 'https://your-backend-service.com' + request.url.split('/').slice(3).join('/');
  const init = {
    method: request.method,
    headers: request.headers,
    body: request.body,
    redirect: 'follow'
  }

  try {
    const response = await fetch(url, init)
    
    // Copy the original headers and add CORS headers
    const newHeaders = new Headers(response.headers)
    for (const [key, value] of Object.entries(corsHeaders)) {
      newHeaders.set(key, value)
    }

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: newHeaders
    })
  } catch (error) {
    return new Response(JSON.stringify({ error: 'Failed to fetch from backend' }), {
      status: 500,
      headers: corsHeaders
    })
  }
}